#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int* arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &arr[i]);
        }
        int g = arr[0];
        for (int i = 1; i < N; i++) {
            g = gcd(g, arr[i]);
        }
        if (g > 1) {
            int ans = 0;
            for (int i = 1; i < N; i++) {
                if (arr[i] < arr[i - 1]) {
                    ans += arr[i - 1] - arr[i];
                    arr[i] = arr[i - 1];
                }
            }
            printf("%d\n", ans);
        } else {
            int ans = INT_MAX;
            for (int i = 2; i <= 10000; i++) {
                int temp = 0;
                for (int j = 0; j < N; j++) {
                    temp += (i - arr[j] % i) % i;
                }
                ans = (ans < temp) ? ans : temp;
            }
            printf("%d\n", ans);
        }
        free(arr);
    }
    return 0;
}

