        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = sc.nextInt();
            }
            int g = arr[0];
            for (int i = 1; i < N; i++) {
                g = gcd(g, arr[i]);
            }
            if (g > 1) {
                int ans = 0;
                for (int i = 1; i < N; i++) {
                    if (arr[i] < arr[i - 1]) {
                        ans += arr[i - 1] - arr[i];
                        arr[i] = arr[i - 1];
                    }
                }
                System.out.println(ans);
            } else {
                int ans = Integer.MAX_VALUE;
                for (int i = 2; i <= 10000; i++) {
                    int temp = 0;
                    for (int j = 0; j < N; j++) {
                        temp += (i - arr[j] % i) % i;
                    }
                    ans = (ans < temp) ? ans : temp;
                }
                System.out.println(ans);
            }
        }
    }
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
